-- {"operators": "INNER_JOIN,AGGREGATE", "complexity": "medium", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": true, "tables": "STOCK,ORDER_LINE", "ducklake": true}
SELECT s.S_W_ID, s.S_I_ID, s.S_QUANTITY AS current_qty, SUM(CASE WHEN ol.OL_DELIVERY_D IS NULL THEN ol.OL_QUANTITY ELSE 0 END) AS pending_qty, SUM(ol.OL_QUANTITY) AS total_ordered FROM dl.STOCK s JOIN dl.ORDER_LINE ol ON s.S_W_ID = ol.OL_SUPPLY_W_ID AND s.S_I_ID = ol.OL_I_ID GROUP BY s.S_W_ID, s.S_I_ID, s.S_QUANTITY;
